{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[{"file_id":"1-XYLvxVYPlqt8mLdBu1IprcOMndGTDGX","timestamp":1749232821500}],"authorship_tag":"ABX9TyP6BTLYUgGiXHj1th8yZTL7"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"m7nGukRSZmCK"},"outputs":[],"source":["import google.generativeai as genai\n","from langgraph.graph import StateGraph, END\n","from typing import TypedDict, List, Dict\n","import json\n","import re\n","import os\n","from datetime import datetime\n","from google.cloud import storage\n","import uuid\n","import logging\n","import tempfile\n","import sys\n","\n","# --- Configuration ---\n","# Basic logging setup\n","logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')\n","logger = logging.getLogger(__name__)\n","\n","# Initialize GenAI Model\n","# On Vertex AI, authentication is handled automatically via Application Default Credentials.\n","# No API key is needed.\n","try:\n","    model = genai.GenerativeModel('gemini-1.5-flash-preview-0514')\n","except Exception as e:\n","    logger.critical(f\"Failed to initialize GenerativeModel. Ensure the environment is authenticated. Error: {e}\")\n","    sys.exit(1)\n","\n","\n","# GCS Configuration from Environment Variables or Defaults\n","INPUT_BUCKET = os.environ.get(\"INPUT_BUCKET\", \"domain-evonance-storage\")\n","INPUT_PREFIX = os.environ.get(\"INPUT_PREFIX\", \"source_documents/\")\n","OUTPUT_BUCKET = os.environ.get(\"OUTPUT_BUCKET\", \"outputjson4pdf\")\n","MAX_PDFS = int(os.environ.get(\"MAX_PDFS\", 10))\n","\n","# Initialize GCS client\n","try:\n","    storage_client = storage.Client()\n","except Exception as e:\n","    logger.critical(f\"Failed to initialize GCS Client. Ensure credentials are set up. Error: {e}\")\n","    sys.exit(1)\n","\n","\n","# --- State and Schemas ---\n","\n","# Document state for LangGraph\n","class DocumentState(TypedDict):\n","    pdf_path: str\n","    doc_type: str\n","    raw_text: str\n","    tables: List[Dict]\n","    json_output: Dict\n","    document_id: str # Relative path of the PDF in the input bucket\n","    ocr_confidences: Dict\n","    genai_confidence_scores: Dict\n","    decision_status: str\n","    overall_confidence_score: float\n","\n","# JSON output schemas\n","schemas = {\n","    \"bank\": {\n","        \"id\": \"\", \"accountType\": \"bank_statement\", \"accountSubType\": \"\", \"accountHolder\": \"\",\n","        \"institutionName\": \"\", \"accountId\": \"\", \"accountStatement\": { \"openingBalance\": 0.0,\n","        \"closingBalance\": 0.0, \"startDate\": \"\", \"endDate\": \"\" }, \"transactions\": [ {\n","        \"transactionType\": \"\", \"transactionAmount\": 0.0, \"transactionDescription\": \"\",\n","        \"transactionDate\": \"\", \"transactionMerchant\": None, \"transactionCategory\": None } ],\n","        \"accountInterestRate\": 0.0\n","    },\n","    \"pay\": {\n","        \"id\": \"\", \"paystubNetPay\": 0.0, \"paystubDate\": \"\", \"paystubGrossPay\": 0.0,\n","        \"payPeriodstartDate\": \"\", \"payPeriodendDate\": \"\", \"paystubFrequency\": \"\",\n","        \"employeeName\": \"\", \"employer\": \"\", \"taxDeductions\": [ { \"taxThisPeriod\": 0.0,\n","        \"taxYtd\": 0.0, \"taxType\": \"\", \"taxName\": \"\" } ], \"otherDeductions\": [ {\n","        \"deductionThisPeriod\": 0.0, \"deductionYtd\": 0.0, \"deductionType\": \"\",\n","        \"deductionName\": \"\", \"deductionTaxType\": \"\" } ]\n","    },\n","    \"loan\": {\n","        \"id\": \"\", \"type\": \"\", \"accountHolder\": \"\", \"institutionName\": \"\",\n","        \"propertyAddress\": \"\", \"interestRate\": 0.0, \"principal\": 0.0, \"interest\": 0.0,\n","        \"escrow\": 0.0, \"totalAmountDue\": 0.0, \"outstandingPrincipal\": 0.0\n","    },\n","    \"brokerage\": {\n","        \"id\": \"\", \"accounts\": [ { \"currentValue\": 0.0, \"accountHolder\": \"\",\n","        \"institutionName\": \"\", \"accountId\": \"\", \"holdings\": [ { \"ticker\": None,\n","        \"averageCost\": None, \"holdingName\": \"\", \"totalShares\": 0.0, \"currentValue\": 0.0,\n","        \"currentTickerPrice\": 0.0 } ], \"statementDate\": \"\" } ]\n","    }\n","}\n","\n","\n","# --- Utility Functions ---\n","\n","def parse_float(value):\n","    if value is None: return 0.0\n","    try:\n","        return float(re.sub(r\"[^0-9.-]\", \"\", str(value)))\n","    except (ValueError, TypeError):\n","        return 0.0\n","\n","def format_date(date_str):\n","    if not date_str or not isinstance(date_str, str): return \"\"\n","    for fmt in [\"%Y-%m-%d\", \"%m/%d/%Y\", \"%m/%d/%y\", \"%B %d, %Y\", \"%b %d, %Y\", \"%b %d %Y\"]:\n","        try:\n","            return datetime.strptime(date_str, fmt).strftime(\"%Y-%m-%d\")\n","        except ValueError:\n","            pass\n","    return date_str # Return original if parsing fails\n","\n","def check_existing_output(document_id: str) -> bool:\n","    \"\"\"Checks if an output file already exists in the output bucket.\"\"\"\n","    base_name = os.path.basename(document_id)\n","    output_filename = f\"{os.path.splitext(base_name)[0]}_output.json\"\n","    bucket = storage_client.bucket(OUTPUT_BUCKET)\n","    return bucket.blob(output_filename).exists()\n","\n","\n","# --- LangGraph Nodes ---\n","\n","def fetch_pdf(state: DocumentState, temp_dir: str) -> DocumentState:\n","    logger.info(f\"Fetching '{state['document_id']}'...\")\n","    try:\n","        full_blob_name = f\"{INPUT_PREFIX}{state['document_id']}\"\n","        local_dir = os.path.join(temp_dir, os.path.dirname(state['document_id']))\n","        os.makedirs(local_dir, exist_ok=True)\n","        local_path = os.path.join(local_dir, os.path.basename(state['document_id']))\n","\n","        bucket = storage_client.bucket(INPUT_BUCKET)\n","        blob = bucket.blob(full_blob_name)\n","        blob.download_to_filename(local_path)\n","        state[\"pdf_path\"] = local_path\n","        logger.info(f\"Successfully downloaded to {local_path}\")\n","    except Exception as e:\n","        logger.error(f\"Error fetching '{state['document_id']}': {e}\")\n","        state[\"pdf_path\"] = \"\"\n","    return state\n","\n","def classify_document(state: DocumentState) -> DocumentState:\n","    if not state[\"pdf_path\"]:\n","        state[\"doc_type\"] = \"bank\" # Default fallback\n","        logger.warning(f\"Classified as 'bank' (default) due to missing file for '{state['document_id']}'\")\n","        return state\n","    try:\n","        logger.info(f\"Classifying '{state['document_id']}'...\")\n","        pdf_file = genai.upload_file(path=state[\"pdf_path\"], mime_type='application/pdf')\n","        prompt = \"Classify this document as one of: bank, pay, loan, brokerage. Return only the single-word type.\"\n","        response = model.generate_content([prompt, pdf_file], request_options={'timeout': 120})\n","        doc_type = response.text.strip().lower()\n","        state[\"doc_type\"] = doc_type if doc_type in schemas else \"bank\"\n","        logger.info(f\"Classified '{state['document_id']}' as '{state['doc_type']}'\")\n","        genai.delete_file(pdf_file.name)\n","    except Exception as e:\n","        logger.error(f\"Classification failed for '{state['document_id']}', defaulting to 'bank'. Error: {e}\")\n","        state[\"doc_type\"] = \"bank\"\n","    return state\n","\n","def extract_text(state: DocumentState) -> DocumentState:\n","    if not state[\"pdf_path\"]:\n","        state[\"raw_text\"] = \"\"\n","        logger.warning(f\"Text extraction skipped: No file for '{state['document_id']}'\")\n","        return state\n","    try:\n","        logger.info(f\"Extracting text from '{state['document_id']}'...\")\n","        pdf_file = genai.upload_file(path=state[\"pdf_path\"], mime_type='application/pdf')\n","        prompt = \"Extract all text from this PDF. Preserve the layout and structure as much as possible.\"\n","        response = model.generate_content([prompt, pdf_file], request_options={'timeout': 300})\n","        state[\"raw_text\"] = response.text.strip()\n","        logger.info(f\"Text extracted for '{state['document_id']}' ({len(state['raw_text'])} chars).\")\n","        genai.delete_file(pdf_file.name)\n","    except Exception as e:\n","        logger.error(f\"Text extraction failed for '{state['document_id']}'. Error: {e}\")\n","        state[\"raw_text\"] = \"\"\n","    # Initialize other fields\n","    state[\"tables\"] = []\n","    state[\"ocr_confidences\"] = {}\n","    return state\n","\n","def parse_normalize(state: DocumentState) -> DocumentState:\n","    doc_type = state[\"doc_type\"]\n","    logger.info(f\"Parsing '{state['document_id']}' as '{doc_type}' document...\")\n","    if not state[\"raw_text\"]:\n","         logger.warning(f\"Parsing skipped: No raw text for '{state['document_id']}'\")\n","         state[\"json_output\"] = {}\n","         return state\n","\n","    schema_template = schemas[doc_type].copy()\n","    schema_template[\"id\"] = str(uuid.uuid4())\n","\n","    prompt = f\"\"\"\n","    Based on the document text, extract structured data into a JSON object.\n","    Strictly follow this JSON schema: {json.dumps(schema_template)}.\n","    - Extract all possible fields.\n","    - Convert monetary values to floats (e.g., 1234.56).\n","    - Format dates as 'YYYY-MM-DD'.\n","    - If a field is not found, use the default from the schema (e.g., empty string, 0.0, null).\n","    - For the 'bank' type, categorize transactions using one of: 'Utilities', 'Rent', 'Investments', 'Food', 'Shopping', 'Transfer', 'Cashback', 'Education', 'Medical', 'Subscription/Software', 'Credit Card Payment', 'Government/Tax', 'Investment/Brokerage', 'Pharmacy', 'Insurance', 'Other Loans', 'Bonus', 'Interest Income', 'Payment', 'Auto Payment', 'Securities', 'Real Estate', 'Tax', 'Subscription', 'Other'.\n","    - Output ONLY the JSON object inside ```json ... ```.\n","\n","    Document Text:\n","    {state['raw_text'][:16000]}\n","    \"\"\"\n","\n","    extracted_data = {}\n","    try:\n","        response = model.generate_content(prompt, request_options={'timeout': 300})\n","        json_match = re.search(r\"```json\\n([\\s\\S]*?)\\n```\", response.text)\n","\n","        if json_match:\n","            extracted_data = json.loads(json_match.group(1))\n","            logger.info(f\"Successfully parsed JSON for '{state['document_id']}'\")\n","        else:\n","            logger.warning(f\"Could not find JSON in LLM response for '{state['document_id']}'\")\n","            extracted_data = {}\n","\n","    except (Exception, json.JSONDecodeError) as e:\n","        logger.error(f\"Parsing/Normalization failed for '{state['document_id']}'. Error: {e}\")\n","        extracted_data = {}\n","\n","    # Final assignment\n","    state[\"json_output\"] = {\n","        \"document_id\": state[\"document_id\"],\n","        \"doc_type\": doc_type,\n","        \"data\": extracted_data\n","    }\n","    return state\n","\n","\n","def evaluate_confidence(state: DocumentState) -> DocumentState:\n","    if not state.get(\"json_output\") or not state[\"json_output\"].get(\"data\"):\n","        state.update({\n","            \"genai_confidence_scores\": {}, \"decision_status\": \"rejected\",\n","            \"overall_confidence_score\": 0.0\n","        })\n","        logger.warning(f\"Confidence evaluation skipped: No data for '{state['document_id']}'\")\n","        return state\n","\n","    logger.info(f\"Evaluating confidence for '{state['document_id']}'...\")\n","    prompt = f\"\"\"\n","    Evaluate the confidence (0.0 to 1.0) of each extracted field in the JSON data by comparing it against the raw document text.\n","    - 1.0: Perfect match, directly extracted.\n","    - 0.9: Accurate but required minor formatting/inference.\n","    - 0.5: Ambiguous, partially extracted, or significant inference.\n","    - 0.0: Incorrect or missing.\n","    Return a flat JSON object with dot-notation keys (e.g., 'accounts[0].currentValue': 0.9). Score ALL fields.\n","    Output ONLY the JSON object inside ```json ... ```.\n","\n","    Raw Text (first 4000 chars):\n","    {state['raw_text'][:4000]}\n","\n","    Extracted JSON:\n","    {json.dumps(state['json_output']['data'], indent=2)}\n","    \"\"\"\n","    confidence_scores = {}\n","    try:\n","        response = model.generate_content(prompt, request_options={'timeout': 180})\n","        json_match = re.search(r\"```json\\n([\\s\\S]*?)\\n```\", response.text)\n","        if json_match:\n","            confidence_scores = json.loads(json_match.group(1))\n","        else:\n","            raise ValueError(\"No JSON found in confidence response.\")\n","    except Exception as e:\n","        logger.error(f\"Confidence evaluation failed for '{state['document_id']}': {e}\")\n","        # Fallback: assign 0.0 to all keys if API fails\n","        # (This logic would need a function to flatten the state['json_output']['data'] keys)\n","        confidence_scores = {}\n","\n","    state[\"genai_confidence_scores\"] = confidence_scores\n","    return state\n","\n","def make_decision(state: DocumentState) -> DocumentState:\n","    scores = state.get(\"genai_confidence_scores\", {})\n","    if scores and isinstance(scores, dict):\n","        numeric_scores = [s for s in scores.values() if isinstance(s, (int, float))]\n","        overall_confidence = sum(numeric_scores) / len(numeric_scores) if numeric_scores else 0.0\n","    else:\n","        overall_confidence = 0.0\n","\n","    state[\"overall_confidence_score\"] = overall_confidence\n","    state[\"decision_status\"] = \"accepted\" if overall_confidence >= 0.70 else \"rejected\"\n","    logger.info(f\"Decision for '{state['document_id']}': {state['decision_status']} (Score: {overall_confidence:.2f})\")\n","    return state\n","\n","def save_output(state: DocumentState) -> DocumentState:\n","    \"\"\"Saves the final accepted JSON to the output GCS bucket.\"\"\"\n","    base_name = os.path.basename(state['document_id'])\n","    output_filename = f\"{os.path.splitext(base_name)[0]}_output.json\"\n","    try:\n","        bucket = storage_client.bucket(OUTPUT_BUCKET)\n","        blob = bucket.blob(output_filename)\n","\n","        # Add metadata to the final JSON\n","        final_output = state[\"json_output\"]\n","        final_output[\"processing_metadata\"] = {\n","            \"decision_status\": state[\"decision_status\"],\n","            \"overall_confidence_score\": state[\"overall_confidence_score\"],\n","            \"processing_timestamp_utc\": datetime.utcnow().isoformat(),\n","            \"model_used\": model.model_name,\n","        }\n","\n","        blob.upload_from_string(\n","            json.dumps(final_output, indent=2),\n","            content_type='application/json'\n","        )\n","        logger.info(f\"Saved output to gs://{OUTPUT_BUCKET}/{output_filename}\")\n","    except Exception as e:\n","        logger.error(f\"Error saving output for '{state['document_id']}': {e}\")\n","    return state\n","\n","def cleanup(state: DocumentState) -> DocumentState:\n","    \"\"\"Cleans up the downloaded temporary file.\"\"\"\n","    if state[\"pdf_path\"] and os.path.exists(state[\"pdf_path\"]):\n","        try:\n","            os.remove(state[\"pdf_path\"])\n","            logger.info(f\"Cleaned up temp file: {state['pdf_path']}\")\n","        except OSError as e:\n","            logger.warning(f\"Error removing temp file {state['pdf_path']}: {e}\")\n","    return state\n","\n","# --- Workflow Definition ---\n","\n","def get_workflow(temp_dir: str):\n","    workflow = StateGraph(DocumentState)\n","    workflow.add_node(\"fetch_pdf\", lambda state: fetch_pdf(state, temp_dir))\n","    workflow.add_node(\"classify_document\", classify_document)\n","    workflow.add_node(\"extract_text\", extract_text)\n","    workflow.add_node(\"parse_normalize\", parse_normalize)\n","    workflow.add_node(\"evaluate_confidence\", evaluate_confidence)\n","    workflow.add_node(\"make_decision\", make_decision)\n","    workflow.add_node(\"save_output\", save_output)\n","    workflow.add_node(\"cleanup\", cleanup)\n","\n","    # Build the graph\n","    workflow.set_entry_point(\"fetch_pdf\")\n","    workflow.add_edge(\"fetch_pdf\", \"classify_document\")\n","    workflow.add_edge(\"classify_document\", \"extract_text\")\n","    workflow.add_edge(\"extract_text\", \"parse_normalize\")\n","    workflow.add_edge(\"parse_normalize\", \"evaluate_confidence\")\n","    workflow.add_edge(\"evaluate_confidence\", \"make_decision\")\n","\n","    workflow.add_conditional_edges(\n","        \"make_decision\",\n","        lambda state: \"save_output\" if state[\"decision_status\"] == \"accepted\" else \"cleanup\",\n","        {\"save_output\": \"save_output\", \"cleanup\": \"cleanup\"}\n","    )\n","    workflow.add_edge(\"save_output\", \"cleanup\")\n","    workflow.add_edge(\"cleanup\", END)\n","\n","    return workflow.compile()\n","\n","# --- Main Execution ---\n","\n","def main():\n","    logger.info(\"Starting PDF processing job...\")\n","    logger.info(f\"Input Bucket: gs://{INPUT_BUCKET}/{INPUT_PREFIX}\")\n","    logger.info(f\"Output Bucket: gs://{OUTPUT_BUCKET}/\")\n","\n","    try:\n","        bucket = storage_client.bucket(INPUT_BUCKET)\n","        blobs = bucket.list_blobs(prefix=INPUT_PREFIX)\n","        # Get relative path of each PDF\n","        all_pdfs = [\n","            blob.name[len(INPUT_PREFIX):] for blob in blobs\n","            if blob.name.lower().endswith('.pdf') and blob.name != INPUT_PREFIX\n","        ]\n","        logger.info(f\"Found {len(all_pdfs)} total PDFs in source.\")\n","    except Exception as e:\n","        logger.critical(f\"Fatal: Could not list PDFs from GCS. Error: {e}\")\n","        sys.exit(1)\n","\n","    # Filter out already processed PDFs and limit to MAX_PDFS\n","    pdfs_to_process = [pdf for pdf in all_pdfs if not check_existing_output(pdf)][:MAX_PDFS]\n","\n","    if not pdfs_to_process:\n","        logger.info(\"No new PDFs to process. Job finished.\")\n","        sys.exit(0)\n","\n","    logger.info(f\"Processing {len(pdfs_to_process)} new PDFs: {pdfs_to_process}\")\n","\n","    with tempfile.TemporaryDirectory() as temp_dir:\n","        graph = get_workflow(temp_dir)\n","        for pdf_id in pdfs_to_process:\n","            logger.info(f\"--- Starting workflow for: {pdf_id} ---\")\n","            initial_state = DocumentState(\n","                document_id=pdf_id,\n","                pdf_path=\"\", doc_type=\"\", raw_text=\"\", tables=[], json_output={},\n","                ocr_confidences={}, genai_confidence_scores={}, decision_status=\"\",\n","                overall_confidence_score=0.0\n","            )\n","            try:\n","                graph.invoke(initial_state, {\"recursion_limit\": 10})\n","            except Exception as e:\n","                logger.error(f\"CRITICAL: Unhandled error in workflow for '{pdf_id}'. Error: {e}\")\n","            logger.info(f\"--- Finished workflow for: {pdf_id} ---\")\n","\n","    logger.info(\"Job completed.\")\n","\n","if __name__ == \"__main__\":\n","    main()"]}]}